import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is compound interest?", a: "Compound interest is interest earned on both the original principal and previously earned interest." },
  { q: "What is the compound interest formula?", a: "The formula is A = P(1 + r/n)^(nt), where P is principal, r is annual rate, n is compounding periods per year, and t is years." },
  { q: "What is the Rule of 72?", a: "The Rule of 72 estimates doubling time by dividing 72 by the annual interest rate." },
  { q: "How does compounding frequency affect growth?", a: "More frequent compounding adds interest more often, slightly increasing the final amount compared with annual compounding." },
  { q: "What is the difference between APR and APY?", a: "APR is the stated annual rate. APY reflects the effective annual yield after compounding." },
];
const frequencies = [{ label: "Annually", n: 1 }, { label: "Quarterly", n: 4 }, { label: "Monthly", n: 12 }, { label: "Daily", n: 365 }];
const money = (value: number, digits = 0) => formatCurrencyValue(value, { maximumFractionDigits: digits });
function compound(p: number, r: number, n: number, years: number) { return p * Math.pow(1 + r / 100 / n, n * years); }
export default function CompoundInterestCalculator() {
  useCurrencyVersion();
  const [principal, setPrincipal] = useState(10000);
  const [rate, setRate] = useState(6);
  const [frequency, setFrequency] = useState(12);
  const [years, setYears] = useState(20);
  const finalAmount = compound(principal, rate, frequency, years);
  const totalInterest = finalAmount - principal;
  const yearRows = useMemo(() => Array.from({ length: years + 1 }, (_, year) => ({ year, value: compound(principal, rate, frequency, year), interest: compound(principal, rate, frequency, year) - principal })), [principal, rate, frequency, years]);
  const annualBase = compound(10000, 6, 1, 20);
  const comparisonRows = frequencies.map((f) => ({ ...f, value: compound(10000, 6, f.n, 20), interest: compound(10000, 6, f.n, 20) - 10000, diff: compound(10000, 6, f.n, 20) - annualBase }));
  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
  return (
    <>
      <SEOHead title="Free Compound Interest Calculator Online - Calculate Compound Growth Instantly | CalcHive" description="Free online compound interest calculator. Calculate compound interest for any principal, rate and compounding frequency with year by year breakdown instantly. 100% free, no signup required." canonical="/compound-interest-calculator" keywords="free compound interest calculator, compound interest calculator online free, calculate compound interest free, daily compound interest calculator free, monthly compounding calculator free" category="Financial Calculators" breadcrumbName="Free Compound Interest Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Compound Interest Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate compound growth by principal, rate, compounding frequency, and time period.</p></div><AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold text-foreground block mb-2">Principal</label><input type="number" value={principal} onChange={(e) => setPrincipal(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Annual interest rate (%)</label><input type="number" step="0.1" value={rate} onChange={(e) => setRate(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Compounding frequency</label><select value={frequency} onChange={(e) => setFrequency(Number(e.target.value))} className={inputClass}>{frequencies.map((f) => <option key={f.n} value={f.n}>{f.label}</option>)}</select></div><div><label className="text-sm font-semibold text-foreground block mb-2">Time period (years)</label><input type="number" value={years} onChange={(e) => setYears(Number(e.target.value))} className={inputClass} /></div></div><motion.div key={`${principal}-${rate}-${frequency}-${years}`} initial={{ opacity: .7, y: 4 }} animate={{ opacity: 1, y: 0 }}><div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Final Amount</p><p className="text-5xl sm:text-6xl font-black text-white" data-testid="result-compound">{money(finalAmount)}</p></div><div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total interest earned</p><p className="text-lg font-extrabold text-foreground">{money(totalInterest)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Growth multiple</p><p className="text-lg font-extrabold text-foreground">{(finalAmount / principal).toFixed(2)}x</p></div></div></motion.div></section><ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate Compound Interest for Free</h2><p className="text-muted-foreground leading-relaxed">Use A = P(1 + r/n)^(nt) to calculate compound interest for any principal, rate, frequency, and time.</p><h2 className="text-2xl font-bold text-foreground">How Compounding Frequency Affects Your Final Amount</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">How Compounding Frequency Affects $10,000 at 6% Over 20 Years</caption><thead className="bg-muted/60"><tr>{["Compounding Frequency", "Final Amount", "Total Interest", "Difference from Annual"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{comparisonRows.map((row) => <tr key={row.n}><td className="py-2.5 px-3 font-semibold">{row.label}</td><td className="py-2.5 px-3">{money(row.value)}</td><td className="py-2.5 px-3">{money(row.interest)}</td><td className="py-2.5 px-3">{money(row.diff)}</td></tr>)}</tbody></table></div><h2 className="text-2xl font-bold text-foreground">Free Compound Growth Calculator for Everyone</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Year by Year Breakdown</caption><thead className="bg-muted/60"><tr>{["Year", "Balance", "Interest Earned"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{yearRows.map((row) => <tr key={row.year}><td className="py-2.5 px-3 font-semibold">{row.year}</td><td className="py-2.5 px-3 text-sky-600 dark:text-sky-400">{money(row.value)}</td><td className="py-2.5 px-3">{money(row.interest)}</td></tr>)}</tbody></table></div></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/compound-interest-calculator" headingLevel="h3" /></main>
    </>
  );
}


